#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using System.Linq;
using System.Xml;
using MVZ2.IO;
using MVZ2.Talk;

namespace MVZ2.TalkData
{
    public class TalkSection
    {
        public string archiveText = string.Empty;
        public bool canAutoSkip;
        public TalkScript[]? startScripts;
        public TalkScript[]? autoSkipScripts;
        public TalkScript[]? skipScripts;
        public TalkCharacter[] characters;
        public TalkSentence[] sentences;

        private TalkSection(TalkScript[]? startScripts, TalkScript[]? autoSkipScripts, TalkScript[]? skipScripts, TalkCharacter[] characters, TalkSentence[] sentences)
        {
            this.startScripts = startScripts;
            this.skipScripts = skipScripts;
            this.autoSkipScripts = autoSkipScripts;
            this.characters = characters;
            this.sentences = sentences;
        }

        public XmlNode ToXmlNode(XmlDocument document)
        {
            XmlNode node = document.CreateElement("section");
            if (!canAutoSkip)
            {
                node.CreateAttribute("canAutoSkip", false.ToString());
            }

            document.CreateTalkScriptNodes(node, "onStart", startScripts, "分段开始脚本");
            document.CreateTalkScriptNodes(node, "onAutoSkip", autoSkipScripts, "分段自动跳过脚本");
            document.CreateTalkScriptNodes(node, "onSkip", skipScripts, "分段跳过脚本");

            if (!string.IsNullOrEmpty(archiveText))
            {
                document.AddComment(node, "对话档案文本");
                document.CreateTextOrCDataNode(node, "text", archiveText);
            }

            document.AddComment(node, "角色列表");
            var charactersNode = document.CreateElement("characters");
            foreach (var character in characters)
            {
                var child = character.ToXmlNode(document);
                charactersNode.AppendChild(child);
            }
            node.AppendChild(charactersNode);

            document.AddComment(node, "语句列表");
            var sentencesNode = document.CreateElement("sentences");
            for (int i = 0; i < sentences.Length; i++)
            {
                var sentence = sentences[i];
                document.AddComment(sentencesNode, $"语句{i}");
                var child = sentence.ToXmlNode(document);
                sentencesNode.AppendChild(child);
            }
            node.AppendChild(sentencesNode);
            
            return node;
        }
        public static TalkSection FromXmlNode(XmlNode node, string defaultNsp)
        {
            var canAutoSkip = node.GetAttributeBool("canAutoSkip") ?? true;

            var startScriptsNode = node["onStart"];
            TalkScript[]? startScripts;
            if (startScriptsNode != null)
            {
                startScripts = TalkScript.FromArrayXmlNode(startScriptsNode);
            }
            else
            {
                startScripts = TalkScript.ParseArray(node.GetAttribute("onStart"));
            }

            var autoSkipScriptsNode = node["onAutoSkip"];
            TalkScript[]? autoSkipScripts;
            if (autoSkipScriptsNode != null)
            {
                autoSkipScripts = TalkScript.FromArrayXmlNode(autoSkipScriptsNode);
            }
            else
            {
                autoSkipScripts = TalkScript.ParseArray(node.GetAttribute("onAutoSkip"));
            }


            var skipScriptsNode = node["onSkip"];
            TalkScript[]? skipScripts;
            if (skipScriptsNode != null)
            {
                skipScripts = TalkScript.FromArrayXmlNode(skipScriptsNode);
            }
            else
            {
                skipScripts = TalkScript.ParseArray(node.GetAttribute("onSkip"));
            }

            var textNode = node["text"];
            string archiveText = string.Empty;
            if (textNode != null)
            {
                archiveText = textNode.InnerText;
            }

            var charactersNode = node["characters"];
            List<TalkCharacter> characters = new List<TalkCharacter>();
            if (charactersNode != null)
            {
                var characterChildren = charactersNode.ChildNodes;
                for (int i = 0; i < characterChildren.Count; i++)
                {
                    var child = characterChildren[i];
                    var meta = TalkCharacter.FromXmlNode(child, defaultNsp);
                    if (meta != null)
                        characters.Add(meta);
                }
            }
            var sentencesNode = node["sentences"];
            List<TalkSentence> sentences = new List<TalkSentence>();
            if (sentencesNode != null)
            {
                var sentenceChildren = sentencesNode.ChildNodes;
                for (int i = 0; i < sentenceChildren.Count; i++)
                {
                    var child = sentenceChildren[i];
                    var meta = TalkSentence.FromXmlNode(child, defaultNsp);
                    if (meta != null)
                        sentences.Add(meta);
                }
            }
            return new TalkSection(startScripts, autoSkipScripts, skipScripts, characters.ToArray(), sentences.ToArray())
            {
                canAutoSkip = canAutoSkip,
                archiveText = archiveText,
            };
        }
    }
}
